SELECT AVG(fiscal_freedom) AS average_fiscal_freedom
FROM economic_freedom
WHERE year = 2000;

SELECT AVG(fiscal_freedom) AS average_fiscal_freedom
FROM economic_freedom
WHERE country_id = 0 AND year = 2022;

SELECT country_id, AVG(fiscal_freedom) AS average_fiscal_freedom
FROM economic_freedom
GROUP BY country_id;

SELECT country_id, year, gender_equality, healthcare_quality
FROM social_indicators
WHERE conflicts > 5;

SELECT country_id, fiscal_freedom
FROM economic_freedom
WHERE fiscal_freedom = (SELECT MAX(fiscal_freedom) FROM economic_freedom);

SELECT women_security_safety 
FROM media_and_society
WHERE year = 2020;

SELECT MIN(laws_regulations_media_content) AS lowest_laws_regulations_score
FROM media_and_society
WHERE year = 1;

SELECT AVG(country_count) AS average_countries
FROM (
    SELECT user_id, COUNT(DISTINCT country_id) AS country_count
    FROM access_logs
    GROUP BY user_id
) AS user_country_counts;

SELECT country_id, criminal_justice, public_protests
FROM media_and_society
ORDER BY criminal_justice DESC;

SELECT country_id, fiscal_freedom
FROM economic_freedom
WHERE fiscal_freedom > (SELECT AVG(fiscal_freedom) FROM economic_freedom);

SELECT year
FROM economic_freedom
ORDER BY fiscal_freedom DESC;

SELECT year, AVG(fiscal_freedom) AS Avg_Fiscal_Freedom
FROM economic_freedom
GROUP BY year;

SELECT country_id, conflicts
FROM social_indicators
WHERE conflicts = (SELECT MAX(conflicts) FROM social_indicators);
